I solved it using MaxHeap+Pair.

public class Main {


    static int calculate(int nums[][],int n)
    {
        PriorityQueue<Pair<Integer,Integer>> pq=new PriorityQueue<>((c1, c2) -> (c2.getKey() - c1.getKey()));

        int cnt=0,y=0,x=0;
        for(int i=0;i<n;i++)
        {
            pq.offer(new Pair<>(nums[i][0]+nums[i][1],i));
            y+=nums[i][0];
        }
        while(!pq.isEmpty() && x<=y)
        {
            Pair<Integer,Integer>p=pq.poll();
            x+=p.getKey();
            y-=nums[p.getValue()][0];
            cnt++;
        }
        return cnt;
    }
    public static void main(String[] args) {
        Scanner scan=new Scanner(System.in);
        int n=scan.nextInt();
        int nums[][]=new int[n][2];
        for(int i=0;i<n;i++)
        {
            nums[i][0]=scan.nextInt();
            nums[i][1]=scan.nextInt();
        }
        int ans=calculate(nums,n);
        System.out.println(ans);
    }
}
